// AbstractAccountTypesTestSuite provides comprehensive testing for the abstract account types package.
// This test suite covers:
// - Parameter creation and validation (NewParams, DefaultParams)
// - Parameter validation logic (Validate method)
// - Code ID allowlist functionality (IsAllowed method)
// - Edge cases and error conditions
// - Direct parameter struct manipulation and validation
type AbstractAccountTypesTestSuite struct {
	suite.Suite
}

// SetupTest prepares the test suite
func (s *AbstractAccountTypesTestSuite) SetupTest() {
	// Setup can be added here if needed for future tests
}

// TestDefaultParams tests the default parameter creation
func (s *AbstractAccountTypesTestSuite) TestDefaultParams() {
	params := types.DefaultParams()

	s.Require().NotNil(params)
	s.Require().True(params.AllowAllCodeIDs)
	s.Require().Empty(params.AllowedCodeIDs)
	s.Require().Equal(uint64(types.DefaultMaxGas), params.MaxGasBefore)
	s.Require().Equal(uint64(types.DefaultMaxGas), params.MaxGasAfter)

	// Default params should be valid
	s.Require().NoError(params.Validate())
}

// TestNewParamsValid tests valid parameter creation
func (s *AbstractAccountTypesTestSuite) TestNewParamsValid() {
	testCases := []struct {
		name            string
		allowAllCodeIDs bool
		allowedCodeIDs  []uint64
		maxGasBefore    uint64
		maxGasAfter     uint64
		expectError     bool
	}{
		{
			name:            "allow all code IDs with empty list",
			allowAllCodeIDs: true,
			allowedCodeIDs:  []uint64{},
			maxGasBefore:    1000000,
			maxGasAfter:     2000000,
			expectError:     false,
		},
		{
			name:            "disallow all with sorted allowed list",
			allowAllCodeIDs: false,
			allowedCodeIDs:  []uint64{1, 5, 10, 20},
			maxGasBefore:    500000,
			maxGasAfter:     1000000,
			expectError:     false,
		},
		{
			name:            "single allowed code ID",
			allowAllCodeIDs: false,
			allowedCodeIDs:  []uint64{42},
			maxGasBefore:    types.DefaultMaxGas,
			maxGasAfter:     types.DefaultMaxGas,
			expectError:     false,
		},
	}

	for _, tc := range testCases {
		s.Run(tc.name, func() {
			params, err := types.NewParams(tc.allowAllCodeIDs, tc.allowedCodeIDs, tc.maxGasBefore, tc.maxGasAfter)

			if tc.expectError {
				s.Require().Error(err)
				s.Require().Nil(params)
			} else {
				s.Require().NoError(err)
				s.Require().NotNil(params)
				s.Require().Equal(tc.allowAllCodeIDs, params.AllowAllCodeIDs)
				s.Require().Equal(tc.allowedCodeIDs, params.AllowedCodeIDs)
				s.Require().Equal(tc.maxGasBefore, params.MaxGasBefore)
				s.Require().Equal(tc.maxGasAfter, params.MaxGasAfter)
			}
		})
	}
}

// TestParamsValidateInvalid tests parameter validation with invalid inputs
func (s *AbstractAccountTypesTestSuite) TestParamsValidateInvalid() {
	testCases := []struct {
		name            string
		allowAllCodeIDs bool
		allowedCodeIDs  []uint64
		maxGasBefore    uint64
		maxGasAfter     uint64
		expectedError   error
	}{
		{
			name:            "zero max gas before",
			allowAllCodeIDs: true,
			allowedCodeIDs:  []uint64{},
			maxGasBefore:    0,
			maxGasAfter:     1000000,
			expectedError:   types.ErrZeroMaxGas,
		},
		{
			name:            "zero max gas after",
			allowAllCodeIDs: true,
			allowedCodeIDs:  []uint64{},
			maxGasBefore:    1000000,
			maxGasAfter:     0,
			expectedError:   types.ErrZeroMaxGas,
		},
		{
			name:            "allow all with non-empty list",
			allowAllCodeIDs: true,
			allowedCodeIDs:  []uint64{1, 2, 3},
			maxGasBefore:    1000000,
			maxGasAfter:     1000000,
			expectedError:   types.ErrNonEmptyAllowList,
		},
		{
			name:            "unsorted allowed list",
			allowAllCodeIDs: false,
			allowedCodeIDs:  []uint64{5, 1, 10},
			maxGasBefore:    1000000,
			maxGasAfter:     1000000,
			expectedError:   types.ErrMalformedAllowList,
		},
		{
			name:            "duplicate allowed code IDs",
			allowAllCodeIDs: false,
			allowedCodeIDs:  []uint64{1, 5, 5, 10},
			maxGasBefore:    1000000,
			maxGasAfter:     1000000,
			expectedError:   types.ErrMalformedAllowList,
		},
		{
			name:            "zero in allowed list",
			allowAllCodeIDs: false,
			allowedCodeIDs:  []uint64{0, 1, 5},
			maxGasBefore:    1000000,
			maxGasAfter:     1000000,
			expectedError:   types.ErrMalformedAllowList,
		},
	}

	for _, tc := range testCases {
		s.Run(tc.name, func() {
			params, err := types.NewParams(tc.allowAllCodeIDs, tc.allowedCodeIDs, tc.maxGasBefore, tc.maxGasAfter)
			s.Require().Error(err)
			s.Require().NotNil(params) // params struct is returned even on validation failure
			s.Require().ErrorIs(err, tc.expectedError)
		})
	}
}

// TestParamsIsAllowed tests the IsAllowed method
func (s *AbstractAccountTypesTestSuite) TestParamsIsAllowed() {
	testCases := []struct {
		name            string
		allowAllCodeIDs bool
		allowedCodeIDs  []uint64
		testCodeID      uint64
		expectedResult  bool
	}{
		{
			name:            "allow all - any code ID allowed",
			allowAllCodeIDs: true,
			allowedCodeIDs:  []uint64{},
			testCodeID:      999,
			expectedResult:  true,
		},
		{
			name:            "allow all - zero code ID allowed",
			allowAllCodeIDs: true,
			allowedCodeIDs:  []uint64{},
			testCodeID:      0,
			expectedResult:  true,
		},
		{
			name:            "restricted list - allowed code ID",
			allowAllCodeIDs: false,
			allowedCodeIDs:  []uint64{1, 5, 10, 20},
			testCodeID:      5,
			expectedResult:  true,
		},
		{
			name:            "restricted list - first code ID",
			allowAllCodeIDs: false,
			allowedCodeIDs:  []uint64{1, 5, 10, 20},
			testCodeID:      1,
			expectedResult:  true,
		},
		{
			name:            "restricted list - last code ID",
			allowAllCodeIDs: false,
			allowedCodeIDs:  []uint64{1, 5, 10, 20},
			testCodeID:      20,
			expectedResult:  true,
		},
		{
			name:            "restricted list - disallowed code ID",
			allowAllCodeIDs: false,
			allowedCodeIDs:  []uint64{1, 5, 10, 20},
			testCodeID:      15,
			expectedResult:  false,
		},
		{
			name:            "restricted list - zero code ID not in list",
			allowAllCodeIDs: false,
			allowedCodeIDs:  []uint64{1, 5, 10, 20},
			testCodeID:      0,
			expectedResult:  false,
		},
		{
			name:            "empty allowed list - nothing allowed",
			allowAllCodeIDs: false,
			allowedCodeIDs:  []uint64{},
			testCodeID:      1,
			expectedResult:  false,
		},
	}

	for _, tc := range testCases {
		s.Run(tc.name, func() {
			params, err := types.NewParams(tc.allowAllCodeIDs, tc.allowedCodeIDs, types.DefaultMaxGas, types.DefaultMaxGas)
			s.Require().NoError(err)
			s.Require().NotNil(params)

			result := params.IsAllowed(tc.testCodeID)
			s.Require().Equal(tc.expectedResult, result)
		})
	}
}

// TestParamsValidateEdgeCases tests edge cases in parameter validation
func (s *AbstractAccountTypesTestSuite) TestParamsValidateEdgeCases() {
	s.Run("maximum valid values", func() {
		params, err := types.NewParams(true, []uint64{}, ^uint64(0), ^uint64(0)) // max uint64
		s.Require().NoError(err)
		s.Require().NotNil(params)
	})

	s.Run("minimum valid gas values", func() {
		params, err := types.NewParams(true, []uint64{}, 1, 1)
		s.Require().NoError(err)
		s.Require().NotNil(params)
	})

	s.Run("large allowed list", func() {
		// Create a large sorted list
		allowedList := make([]uint64, 1000)
		for i := range allowedList {
			allowedList[i] = uint64(i + 1) // 1, 2, 3, ..., 1000
		}

		params, err := types.NewParams(false, allowedList, types.DefaultMaxGas, types.DefaultMaxGas)
		s.Require().NoError(err)
		s.Require().NotNil(params)

		// Test that all IDs are allowed
		for i := uint64(1); i <= 1000; i++ {
			s.Require().True(params.IsAllowed(i))
		}

		// Test that IDs outside the range are not allowed
		s.Require().False(params.IsAllowed(0))
		s.Require().False(params.IsAllowed(1001))
	})
}

// TestParamsDirectValidation tests direct validation of params struct
func (s *AbstractAccountTypesTestSuite) TestParamsDirectValidation() {
	s.Run("valid default params", func() {
		params := types.DefaultParams()
		err := params.Validate()
		s.Require().NoError(err)
	})

	s.Run("modify params to invalid state", func() {
		params := types.DefaultParams()

		// Make it invalid by setting both AllowAllCodeIDs and having a non-empty list
		params.AllowAllCodeIDs = true
		params.AllowedCodeIDs = []uint64{1, 2, 3}

		err := params.Validate()
		s.Require().Error(err)
		s.Require().ErrorIs(err, types.ErrNonEmptyAllowList)
	})
}

// TestTransactionValidation tests transaction message validation
func (s *AbstractAccountTypesTestSuite) TestTransactionValidation() {
	// Generate valid test addresses
	testAddr := sdk.AccAddress(secp256k1.GenPrivKey().PubKey().Address())
	invalidAddr := "invalid-address"

	s.Run("MsgUpdateParams validation", func() {
		// Valid message
		validMsg := &types.MsgUpdateParams{
			Sender: testAddr.String(),
			Params: types.DefaultParams(),
		}
		err := validMsg.ValidateBasic()
		s.Require().NoError(err)

		// Test GetSigners
		signers := validMsg.GetSigners()
		s.Require().Len(signers, 1)
		s.Require().Equal(testAddr, signers[0])

		// Invalid sender address
		invalidMsg := &types.MsgUpdateParams{
			Sender: invalidAddr,
			Params: types.DefaultParams(),
		}
		err = invalidMsg.ValidateBasic()
		s.Require().Error(err)
		s.Require().Contains(err.Error(), "invalid sender address")

		// Invalid params in message
		invalidParamsMsg := &types.MsgUpdateParams{
			Sender: testAddr.String(),
			Params: &types.Params{
				AllowAllCodeIDs: true,
				AllowedCodeIDs:  []uint64{1, 2, 3}, // Invalid: non-empty list with AllowAll=true
				MaxGasBefore:    1000000,
				MaxGasAfter:     1000000,
			},
		}
		err = invalidParamsMsg.ValidateBasic()
		s.Require().Error(err)
		s.Require().ErrorIs(err, types.ErrNonEmptyAllowList)
	})

	s.Run("MsgRegisterAccount validation", func() {
		validCoins := sdk.NewCoins(sdk.NewCoin("utoken", math.NewInt(1000)))

		// Valid message
		validMsg := &types.MsgRegisterAccount{
			Sender: testAddr.String(),
			CodeID: 1,
			Msg:    []byte(`{"pubkey": "test"}`),
			Funds:  validCoins,
			Salt:   []byte("test-salt"),
		}
		err := validMsg.ValidateBasic()
		s.Require().NoError(err)

		// Test GetSigners
		signers := validMsg.GetSigners()
		s.Require().Len(signers, 1)
		s.Require().Equal(testAddr, signers[0])

		// Invalid sender address
		invalidSenderMsg := &types.MsgRegisterAccount{
			Sender: invalidAddr,
			CodeID: 1,
			Msg:    []byte(`{}`),
			Funds:  nil,
			Salt:   []byte("salt"),
		}
		err = invalidSenderMsg.ValidateBasic()
		s.Require().Error(err)
		s.Require().Contains(err.Error(), "invalid sender address")

		// Invalid code ID (zero)
		zeroCodeMsg := &types.MsgRegisterAccount{
			Sender: testAddr.String(),
			CodeID: 0,
			Msg:    []byte(`{}`),
			Funds:  nil,
			Salt:   []byte("salt"),
		}
		err = zeroCodeMsg.ValidateBasic()
		s.Require().Error(err)
		s.Require().Contains(err.Error(), "code id cannot be zero")

		// Invalid init message (malformed JSON)
		invalidInitMsg := &types.MsgRegisterAccount{
			Sender: testAddr.String(),
			CodeID: 1,
			Msg:    []byte(`{invalid json`), // Malformed JSON
			Funds:  validCoins,
			Salt:   []byte("salt"),
		}
		err = invalidInitMsg.ValidateBasic()
		s.Require().Error(err)
		s.Require().Contains(err.Error(), "invalid init msg")

		// Invalid funds (negative amount)
		invalidFundsMsg := &types.MsgRegisterAccount{
			Sender: testAddr.String(),
			CodeID: 1,
			Msg:    []byte(`{}`),
			Funds:  sdk.Coins{sdk.Coin{Denom: "utoken", Amount: math.NewInt(-1)}}, // Invalid coin
			Salt:   []byte("salt"),
		}
		err = invalidFundsMsg.ValidateBasic()
		s.Require().Error(err)

		// Invalid funds (empty denom)
		invalidDenomMsg := &types.MsgRegisterAccount{
			Sender: testAddr.String(),
			CodeID: 1,
			Msg:    []byte(`{}`),
			Funds:  sdk.Coins{sdk.Coin{Denom: "", Amount: math.NewInt(100)}}, // Empty denom
			Salt:   []byte("salt"),
		}
		err = invalidDenomMsg.ValidateBasic()
		s.Require().Error(err)

		// Invalid salt (too long - this test depends on wasmd's ValidateSalt implementation)
		longSalt := make([]byte, 65) // Assuming max salt length is 64
		for i := range longSalt {
			longSalt[i] = byte('a')
		}
		invalidSaltMsg := &types.MsgRegisterAccount{
			Sender: testAddr.String(),
			CodeID: 1,
			Msg:    []byte(`{}`),
			Funds:  nil,
			Salt:   longSalt,
		}
		err = invalidSaltMsg.ValidateBasic()
		s.Require().Error(err) // Should fail due to salt validation
	})
}

// TestAbstractAccountFunctionality tests the AbstractAccount type
func (s *AbstractAccountTypesTestSuite) TestAbstractAccountFunctionality() {
	testAddr := sdk.AccAddress(secp256k1.GenPrivKey().PubKey().Address())

	s.Run("NewAbstractAccount", func() {
		account := types.NewAbstractAccount(testAddr.String(), 5, 10)

		s.Require().NotNil(account)
		s.Require().Equal(testAddr.String(), account.GetAddress().String())
		s.Require().Equal(uint64(5), account.GetAccountNumber())
		s.Require().Equal(uint64(10), account.GetSequence())
	})

	s.Run("NewAbstractAccountFromAccount", func() {
		// Create a BaseAccount for testing
		baseAccount := authtypes.NewBaseAccount(testAddr, nil, 42, 100)

		account := types.NewAbstractAccountFromAccount(baseAccount)

		s.Require().NotNil(account)
		s.Require().Equal(testAddr.String(), account.GetAddress().String())
		s.Require().Equal(uint64(42), account.GetAccountNumber())
		s.Require().Equal(uint64(100), account.GetSequence())
	})

	s.Run("Address operations", func() {
		account := types.NewAbstractAccount(testAddr.String(), 0, 0)

		// Test GetAddress
		s.Require().Equal(testAddr.String(), account.GetAddress().String())

		// Test SetAddress on fresh account
		freshAccount := &types.AbstractAccount{}
		newAddr := sdk.AccAddress(secp256k1.GenPrivKey().PubKey().Address())
		err := freshAccount.SetAddress(newAddr)
		s.Require().NoError(err)
		s.Require().Equal(newAddr, freshAccount.GetAddress())

		// Test SetAddress error - cannot override existing address
		err = account.SetAddress(newAddr)
		s.Require().Error(err)
		s.Require().Contains(err.Error(), "cannot override AbstractAccount address")
	})

	s.Run("PubKey operations", func() {
		account := types.NewAbstractAccount(testAddr.String(), 0, 0)

		// Test GetPubKey returns NilPubKey
		pubKey := account.GetPubKey()
		s.Require().NotNil(pubKey)
		nilPubKey, ok := pubKey.(*types.NilPubKey)
		s.Require().True(ok)
		s.Require().Equal(testAddr.Bytes(), nilPubKey.AddressBytes)

		// Test SetPubKey error - cannot set pubkey for AbstractAccount
		realPubKey := secp256k1.GenPrivKey().PubKey()
		err := account.SetPubKey(realPubKey)
		s.Require().Error(err)
		s.Require().Contains(err.Error(), "cannot set pubkey for AbstractAccount")
	})

	s.Run("Account number operations", func() {
		account := types.NewAbstractAccount(testAddr.String(), 42, 0)

		// Test GetAccountNumber
		s.Require().Equal(uint64(42), account.GetAccountNumber())

		// Test SetAccountNumber
		account.SetAccountNumber(99)
		s.Require().Equal(uint64(99), account.GetAccountNumber())
	})

	s.Run("Sequence operations", func() {
		account := types.NewAbstractAccount(testAddr.String(), 0, 123)

		// Test GetSequence
		s.Require().Equal(uint64(123), account.GetSequence())

		// Test SetSequence
		account.SetSequence(456)
		s.Require().Equal(uint64(456), account.GetSequence())
	})

	s.Run("Validation", func() {
		// Valid account
		account := types.NewAbstractAccount(testAddr.String(), 1, 1)
		err := account.Validate()
		s.Require().NoError(err)

		// Account with empty address should fail validation
		invalidAccount := types.NewAbstractAccount("", 1, 1)
		err = invalidAccount.Validate()
		s.Require().Error(err)
		s.Require().Contains(err.Error(), "address cannot be empty")

		// Direct test for empty address validation
		emptyAccount := &types.AbstractAccount{
			Address:       "",
			AccountNumber: 1,
			Sequence:      1,
		}
		err = emptyAccount.Validate()
		s.Require().Error(err)
		s.Require().Contains(err.Error(), "address cannot be empty")
	})
}

// TestNilPubKey tests the NilPubKey implementation
func (s *AbstractAccountTypesTestSuite) TestNilPubKey() {
	testAddr := sdk.AccAddress(secp256k1.GenPrivKey().PubKey().Address())
	nilPubKey := types.NewNilPubKey(testAddr.Bytes())

	s.Run("NilPubKey methods", func() {
		// Address should return the address bytes
		s.Require().Equal(testAddr.Bytes(), nilPubKey.Address().Bytes())

		// Bytes should return nil
		s.Require().Nil(nilPubKey.Bytes())

		// VerifySignature should panic
		s.Require().Panics(func() {
			nilPubKey.VerifySignature([]byte("message"), []byte("signature"))
		}, "NilPubKey.VerifySignature should panic")

		// Equals should work correctly
		anotherNilPubKey := types.NewNilPubKey(testAddr.Bytes())
		s.Require().True(nilPubKey.Equals(anotherNilPubKey))

		// Different address should not be equal
		differentAddr := sdk.AccAddress(secp256k1.GenPrivKey().PubKey().Address())
		differentNilPubKey := types.NewNilPubKey(differentAddr.Bytes())
		s.Require().False(nilPubKey.Equals(differentNilPubKey))

		// Should not equal a real pubkey
		realPubKey := secp256k1.GenPrivKey().PubKey()
		s.Require().False(nilPubKey.Equals(realPubKey))

		// Type should return the correct string
		typeResult := nilPubKey.Type()
		s.Require().Contains(typeResult, "NilPubKey")

		// String should not panic and return the address string
		result := nilPubKey.String()
		s.Require().NotEmpty(result)
		s.Require().Equal(testAddr.String(), result)
	})
}

// TestGenesisState tests genesis state functions
func (s *AbstractAccountTypesTestSuite) TestGenesisState() {
	s.Run("NewGenesisState", func() {
		params := types.DefaultParams()
		nextAccountID := uint64(100)

		genesis := types.NewGenesisState(nextAccountID, params)
		s.Require().NotNil(genesis)
		s.Require().Equal(params, genesis.Params)
		s.Require().Equal(nextAccountID, genesis.NextAccountId)
	})

	s.Run("DefaultGenesisState", func() {
		genesis := types.DefaultGenesisState()
		s.Require().NotNil(genesis)
		s.Require().NotNil(genesis.Params)
		s.Require().Equal(uint64(1), genesis.NextAccountId)
	})

	s.Run("GenesisState validation", func() {
		// Valid genesis state
		validGenesis := types.DefaultGenesisState()
		err := validGenesis.Validate()
		s.Require().NoError(err)

		// Invalid genesis state (invalid params)
		invalidGenesis := &types.GenesisState{
			Params: &types.Params{
				AllowAllCodeIDs: true,
				AllowedCodeIDs:  []uint64{1, 2, 3}, // Invalid: non-empty list with AllowAll=true
				MaxGasBefore:    uint64(types.DefaultMaxGas),
				MaxGasAfter:     uint64(types.DefaultMaxGas),
			},
			NextAccountId: 0,
		}
		err = invalidGenesis.Validate()
		s.Require().Error(err)
	})
}

// TestRegisterInterfaces tests the RegisterInterfaces function
func (s *AbstractAccountTypesTestSuite) TestRegisterInterfaces() {
	registry := codectypes.NewInterfaceRegistry()
	types.RegisterInterfaces(registry)

	s.Run("AbstractAccount implements sdk.AccountI", func() {
		// Create an AbstractAccount instance
		baseAddr := sdk.AccAddress("test-address")
		baseAcc := authtypes.NewBaseAccount(baseAddr, &types.NilPubKey{}, 1, 0)
		abstractAcc := types.NewAbstractAccountFromAccount(baseAcc)

		// Test that it can be packed and unpacked as AccountI
		any, err := codectypes.NewAnyWithValue(abstractAcc)
		s.Require().NoError(err)

		var acc sdk.AccountI
		err = registry.UnpackAny(any, &acc)
		s.Require().NoError(err)
		s.Require().NotNil(acc)
		s.Require().IsType(&types.AbstractAccount{}, acc)
	})

	s.Run("NilPubKey implements cryptotypes.PubKey", func() {
		nilPubKey := &types.NilPubKey{}

		// Test that it can be packed and unpacked as PubKey
		any, err := codectypes.NewAnyWithValue(nilPubKey)
		s.Require().NoError(err)

		var pubKey cryptotypes.PubKey
		err = registry.UnpackAny(any, &pubKey)
		s.Require().NoError(err)
		s.Require().NotNil(pubKey)
		s.Require().IsType(&types.NilPubKey{}, pubKey)
	})

	s.Run("MsgRegisterAccount implements sdk.Msg", func() {
		msg := &types.MsgRegisterAccount{
			Sender: "test-sender",
			CodeID: 1,
			Msg:    []byte("test-msg"),
			Funds:  sdk.NewCoins(),
			Salt:   []byte("test-salt"),
		}

		// Test that it can be packed and unpacked as Msg
		any, err := codectypes.NewAnyWithValue(msg)
		s.Require().NoError(err)

		var sdkMsg sdk.Msg
		err = registry.UnpackAny(any, &sdkMsg)
		s.Require().NoError(err)
		s.Require().NotNil(sdkMsg)
		s.Require().IsType(&types.MsgRegisterAccount{}, sdkMsg)
	})

	s.Run("MsgUpdateParams implements sdk.Msg", func() {
		params := types.DefaultParams()
		msg := &types.MsgUpdateParams{
			Sender: "test-sender",
			Params: params,
		}

		// Test that it can be packed and unpacked as Msg
		any, err := codectypes.NewAnyWithValue(msg)
		s.Require().NoError(err)

		var sdkMsg sdk.Msg
		err = registry.UnpackAny(any, &sdkMsg)
		s.Require().NoError(err)
		s.Require().NotNil(sdkMsg)
		s.Require().IsType(&types.MsgUpdateParams{}, sdkMsg)
	})
}

// TestRegisterLegacyAminoCodec tests the RegisterLegacyAminoCodec function
func (s *AbstractAccountTypesTestSuite) TestRegisterLegacyAminoCodec() {
	cdc := codec.NewLegacyAmino()
	types.RegisterLegacyAminoCodec(cdc)

	s.Run("MsgUpdateParams is registered", func() {
		params := types.DefaultParams()
		msg := &types.MsgUpdateParams{
			Sender: "test-sender",
			Params: params,
		}

		// Test marshaling/unmarshaling
		bz, err := cdc.MarshalJSON(msg)
		s.Require().NoError(err)
		s.Require().NotEmpty(bz)

		var decoded types.MsgUpdateParams
		err = cdc.UnmarshalJSON(bz, &decoded)
		s.Require().NoError(err)
		s.Require().Equal(msg.Sender, decoded.Sender)
	})

	s.Run("NilPubKey is registered", func() {
		pubKey := &types.NilPubKey{}

		// Test marshaling/unmarshaling
		bz, err := cdc.MarshalJSON(pubKey)
		s.Require().NoError(err)
		s.Require().NotEmpty(bz)

		var decoded types.NilPubKey
		err = cdc.UnmarshalJSON(bz, &decoded)
		s.Require().NoError(err)
	})

	s.Run("Params is registered", func() {
		params := types.DefaultParams()

		// Test marshaling/unmarshaling
		bz, err := cdc.MarshalJSON(params)
		s.Require().NoError(err)
		s.Require().NotEmpty(bz)

		var decoded types.Params
		err = cdc.UnmarshalJSON(bz, &decoded)
		s.Require().NoError(err)
		s.Require().Equal(params.AllowAllCodeIDs, decoded.AllowAllCodeIDs)
		s.Require().Equal(params.MaxGasBefore, decoded.MaxGasBefore)
		s.Require().Equal(params.MaxGasAfter, decoded.MaxGasAfter)
	})
}

// TestNewAnyFromProtoMsg tests the NewAnyFromProtoMsg function with various protobuf messages
func (s *AbstractAccountTypesTestSuite) TestNewAnyFromProtoMsg() {
	s.Run("Valid MsgUpdateParams", func() {
		msg := &types.MsgUpdateParams{
			Sender: "cosmos1abc123",
			Params: types.DefaultParams(),
		}

		any, err := types.NewAnyFromProtoMsg(msg)
		s.Require().NoError(err)
		s.Require().NotNil(any)
		s.Require().Equal("/abstractaccount.v1.MsgUpdateParams", any.TypeURL)
		s.Require().NotEmpty(any.Value)

		// Verify the marshaled bytes can be unmarshaled back
		var decoded types.MsgUpdateParams
		err = proto.Unmarshal(any.Value, &decoded)
		s.Require().NoError(err)
		s.Require().Equal(msg.Sender, decoded.Sender)
	})

	s.Run("Valid MsgRegisterAccount", func() {
		msg := &types.MsgRegisterAccount{
			Sender: "cosmos1def456",
			CodeID: 1,
			Msg:    []byte("test message"),
			Funds:  []sdk.Coin{sdk.NewInt64Coin("utoken", 1000)},
			Salt:   []byte("test salt"),
		}

		any, err := types.NewAnyFromProtoMsg(msg)
		s.Require().NoError(err)
		s.Require().NotNil(any)
		s.Require().Equal("/abstractaccount.v1.MsgRegisterAccount", any.TypeURL)
		s.Require().NotEmpty(any.Value)

		// Verify the marshaled bytes can be unmarshaled back
		var decoded types.MsgRegisterAccount
		err = proto.Unmarshal(any.Value, &decoded)
		s.Require().NoError(err)
		s.Require().Equal(msg.Sender, decoded.Sender)
		s.Require().Equal(msg.CodeID, decoded.CodeID)
		s.Require().Equal(msg.Msg, decoded.Msg)
		s.Require().Equal(msg.Salt, decoded.Salt)
	})

	s.Run("Valid Params message", func() {
		params := &types.Params{
			AllowAllCodeIDs: true,
			AllowedCodeIDs:  []uint64{1, 2, 3},
			MaxGasBefore:    500000,
			MaxGasAfter:     300000,
		}

		any, err := types.NewAnyFromProtoMsg(params)
		s.Require().NoError(err)
		s.Require().NotNil(any)
		s.Require().Equal("/abstractaccount.v1.Params", any.TypeURL)
		s.Require().NotEmpty(any.Value)

		// Verify the marshaled bytes can be unmarshaled back
		var decoded types.Params
		err = proto.Unmarshal(any.Value, &decoded)
		s.Require().NoError(err)
		s.Require().Equal(params.AllowAllCodeIDs, decoded.AllowAllCodeIDs)
		s.Require().Equal(params.AllowedCodeIDs, decoded.AllowedCodeIDs)
		s.Require().Equal(params.MaxGasBefore, decoded.MaxGasBefore)
		s.Require().Equal(params.MaxGasAfter, decoded.MaxGasAfter)
	})

	s.Run("Standard SDK message", func() {
		// Test with a standard Cosmos SDK message
		msg := &sdk.Coin{
			Denom:  "utoken",
			Amount: math.NewInt(1000),
		}

		any, err := types.NewAnyFromProtoMsg(msg)
		s.Require().NoError(err)
		s.Require().NotNil(any)
		s.Require().Equal("/cosmos.base.v1beta1.Coin", any.TypeURL)
		s.Require().NotEmpty(any.Value)

		// Verify the marshaled bytes can be unmarshaled back
		var decoded sdk.Coin
		err = proto.Unmarshal(any.Value, &decoded)
		s.Require().NoError(err)
		s.Require().Equal(msg.Denom, decoded.Denom)
		s.Require().Equal(msg.Amount, decoded.Amount)
	})

	s.Run("Nil message", func() {
		// This should panic when calling proto.Marshal on nil
		s.Require().Panics(func() {
			_, _ = types.NewAnyFromProtoMsg(nil)
		})
	})
}

// TestNewAnyFromProtoMsg_Standalone tests the function outside of test suite for additional coverage
func TestNewAnyFromProtoMsg_Standalone(t *testing.T) {
	t.Run("Empty message", func(t *testing.T) {
		// Test with an empty but valid message
		msg := &types.MsgUpdateParams{}

		any, err := types.NewAnyFromProtoMsg(msg)
		require.NoError(t, err)
		require.NotNil(t, any)
		require.Equal(t, "/abstractaccount.v1.MsgUpdateParams", any.TypeURL)
		require.NotNil(t, any.Value) // Empty protobuf messages marshal to empty byte slice, not nil

		// Verify it can be unmarshaled
		var decoded types.MsgUpdateParams
		err = proto.Unmarshal(any.Value, &decoded)
		require.NoError(t, err)
	})

	t.Run("Complex nested message", func(t *testing.T) {
		// Create a more complex message to test
		msg := &types.MsgRegisterAccount{
			Sender: "cosmos1example123456789",
			CodeID: 42,
			Msg:    []byte(`{"instantiate": {"admin": "cosmos1admin"}}`),
			Funds: []sdk.Coin{
				sdk.NewInt64Coin("uatom", 1000000),
				sdk.NewInt64Coin("uosmo", 500000),
			},
			Salt: []byte("unique-salt-12345"),
		}

		any, err := types.NewAnyFromProtoMsg(msg)
		require.NoError(t, err)
		require.NotNil(t, any)
		require.Equal(t, "/abstractaccount.v1.MsgRegisterAccount", any.TypeURL)
		require.NotEmpty(t, any.Value)

		// Verify complex structure is preserved
		var decoded types.MsgRegisterAccount
		err = proto.Unmarshal(any.Value, &decoded)
		require.NoError(t, err)
		require.Equal(t, msg.Sender, decoded.Sender)
		require.Equal(t, msg.CodeID, decoded.CodeID)
		require.Equal(t, msg.Msg, decoded.Msg)
		require.Equal(t, len(msg.Funds), len(decoded.Funds))
		require.Equal(t, msg.Funds[0].Denom, decoded.Funds[0].Denom)
		require.Equal(t, msg.Funds[0].Amount, decoded.Funds[0].Amount)
		require.Equal(t, msg.Salt, decoded.Salt)
	})
}

func TestAbstractAccountTypesTestSuite(t *testing.T) {
	suite.Run(t, new(AbstractAccountTypesTestSuite))
}
